with open(md_path, encoding="utf-8") as f:
    md = f.read()

# Truncate long SHA-256 hashes to 16-char prefix + ellipsis in tables for visual fit;
# full hashes remain in ./analysis/ioc_register.csv and ./reports/artifact_manifest.csv
def shorten_hashes(text):
    # SHA-256 is 64 hex chars; MD5 is 32 hex chars
    def repl_sha(m):
        h = m.group(0)
        return h[:16] + "..."
    return re.sub(r"\b[0-9a-fA-F]{64}\b", repl_sha, text)

