import sys, os, re
sys.path.insert(0, "/home/sansforensics/.claude/analysis-scripts")
import markdown
from weasyprint import HTML, CSS
from generate_pdf_report import build_html, CSS_STYLE

md_path = "./reports/CASE-001_base-wkstn-01_report.md"
pdf_path = "./reports/CASE-001_base-wkstn-01_report.pdf"

with open(md_path, encoding="utf-8") as f:
    md = f.read()

def shorten_hashes(text):
    return re.sub(r"\b[0-9a-fA-F]{64}\b", lambda m: m.group(0)[:16] + "...", text)

md_short = shorten_hashes(md)
md_short = md_short.replace("## IOC Table", "## IOC Table\n\n*Note: SHA-256 hashes shown in PDF tables are truncated to first 16 hex chars for visual fit. Full 64-character hashes are in `./analysis/ioc_register.csv` and `./reports/artifact_manifest.csv`. SHA-256 column header below should be read as SHA-256 (truncated).*\n")
md_short = md_short.replace("On-disk component table:**", "On-disk component table** (SHA-256 column is truncated to first 16 chars; full values in artifact_manifest.csv):**")

m = re.search(r"^## Executive Summary", md_short, re.MULTILINE)
body_md = md_short[m.start():] if m else md_short
body_html = markdown.markdown(body_md, extensions=["tables","fenced_code","sane_lists"])

def add_section_nums(html):
    counter = [0]
    def repl(mm):
        counter[0] += 1
        return f"<h2><span class=\"section-num\">{counter[0]:02d}</span> {mm.group(1)}</h2>"
    return re.sub(r"<h2>(.+?)</h2>", repl, html)
body_html = add_section_nums(body_html)

data = {
    "case_id":     "CASE-001 / EVID-001",
    "client":      "shieldbase.lan (host base-wkstn-01)",
    "prepared_by": "DFIR Orchestrator (autonomous SIFT)",
    "date":        "2026-06-04",
    "title":       "Digital Forensic Analysis of base-wkstn-01-c-drive.E01",
    "subtitle":    "Host base-wkstn-01.shieldbase.lan - E01 disk image acquired 2021-09-16",
    "body_html":   body_html,
}

html = build_html(data)

# Stronger override: redefine @page including bottom-left/right footers explicitly
override = r"""
@page {
    size: A4 !important;
    margin: 2.0cm 1.6cm 2.0cm 1.6cm !important;
    @bottom-right {
        content: "Page " counter(page) " of " counter(pages) !important;
        margin-right: 0 !important;
        margin-bottom: 0 !important;
        padding-bottom: 0.4cm !important;
    }
    @bottom-left {
        content: "CONFIDENTIAL - DFIR INTERNAL USE ONLY" !important;
        margin-left: 0 !important;
        margin-bottom: 0 !important;
        padding-bottom: 0.4cm !important;
    }
}
table { font-size: 7.5pt; table-layout: fixed; word-wrap: break-word; overflow-wrap: break-word; width: 100%; }
table th, table td { word-break: break-all; padding: 3pt 4pt; vertical-align: top; }
code { word-break: break-all; }
.cover { padding: 2.8cm 2.2cm 2cm 2.2cm; }
"""

HTML(string=html).write_pdf(pdf_path, stylesheets=[CSS(string=override)], presentational_hints=True)
print(f"PDF written: {pdf_path}")
